import type { QuizQuestion } from '@/lib/types'

export const bookQuizzes: Record<string, QuizQuestion[]> = {
  'atomic-habits': [
    { question: 'According to James Clear, improving just 1% every day results in being how much better after one year?', options: ['10× better', '20× better', '37× better', '100× better'], correctIndex: 2, explanation: 'The math of compounding: 1.01^365 ≈ 37.78. This is the core numerical argument for small habits.', sectionRef: 'The 1% Rule' },
    { question: 'What are the Four Laws of Behavior Change in order?', options: ['Visible, Valued, Viable, Verified', 'Obvious, Attractive, Easy, Satisfying', 'Simple, Sticky, Surprising, Satisfying', 'Cued, Craved, Executed, Rewarded'], correctIndex: 1, explanation: 'The four laws map directly to the four stages of a habit loop: cue (obvious), craving (attractive), response (easy), reward (satisfying).', sectionRef: 'The Four Laws' },
    { question: 'What is "habit stacking"?', options: ['Doing multiple habits at once', 'Attaching a new habit to an existing one', 'Tracking habits on a wall calendar', 'Stacking small wins each day'], correctIndex: 1, explanation: 'Habit stacking: "After I [EXISTING HABIT], I will [NEW HABIT]." It uses existing neural pathways as an anchor.', sectionRef: 'Habit Stacking' },
    { question: 'What does the Two-Minute Rule state?', options: ['Each habit session should last at least 2 minutes', 'New habits should take less than 2 minutes to do', 'You have 2 minutes to start a habit after its cue', 'Track habits every 2 minutes throughout the day'], correctIndex: 1, explanation: 'The two-minute rule scales habits down to their smallest version to remove the friction of starting.', sectionRef: 'The Two-Minute Rule' },
    { question: 'What term describes the period where habits seem to have no effect before a sudden breakthrough?', options: ['The Valley of Disappointment', 'The Plateau of Latent Potential', 'The Trough of Inaction', 'The Habit Gap'], correctIndex: 1, explanation: 'The Plateau of Latent Potential — like ice at 31°F, all the work happens before the visible result appears.', sectionRef: 'The Plateau of Latent Potential' },
    { question: 'Identity-based habits focus on changing:', options: ['Your daily schedule', 'Your outcomes and goals', 'Who you believe you are', 'Your environment design'], correctIndex: 2, explanation: 'Identity-based habits: every action is a vote for the type of person you want to become. "I am a runner" beats "I want to run a marathon."', sectionRef: 'Identity-Based Habits' },
    { question: 'What does "environment design" mean in Atomic Habits?', options: ['Redesigning your workspace for aesthetics', 'Making good habits obvious and bad habits invisible', 'Creating habit-tracking apps', 'Setting phone wallpapers as reminders'], correctIndex: 1, explanation: 'Environment design manipulates cues — visible cues trigger habits. Put the book on the pillow; remove the junk food from the counter.', sectionRef: 'Environment Design' },
    { question: 'What is the "Cardinal Rule of Behavior Change"?', options: ['Never break the chain', 'What is rewarded is repeated; what is punished is avoided', 'Start small and scale up', 'Habits must be tracked to stick'], correctIndex: 1, explanation: 'The cardinal rule: behaviors that are immediately rewarded get repeated; behaviors that are immediately punished get avoided.', sectionRef: 'The Cardinal Rule' },
    { question: 'Never missing twice refers to:', options: ['Always completing a habit two days in a row', 'Immediately returning after missing one day', 'Doing a habit at least twice before quitting', 'Having two backup plans for each habit'], correctIndex: 1, explanation: '"Never miss twice" — missing once is an accident; missing twice is the start of a new (bad) habit. Get back immediately.', sectionRef: 'Never Miss Twice' },
    { question: 'What is the "Goldilocks Rule" in habit formation?', options: ['Habits should be done at the same time each day', 'Humans are motivated by tasks at the edge of their current abilities', 'Habit rewards should be proportional to effort', 'Good habits feel "just right" when properly designed'], correctIndex: 1, explanation: 'The Goldilocks Rule: we are motivated by challenges that are right on the edge of our current ability — not too hard, not too easy.', sectionRef: 'The Goldilocks Rule' },
  ],
  'deep-work': [
    { question: 'How does Cal Newport define "Deep Work"?', options: ['Working on complex topics for long hours', 'Professional activities in distraction-free concentration that push cognitive limits', 'Meditation and mindfulness practices at work', 'Working alone without colleagues'], correctIndex: 1, explanation: 'Deep Work: professional activities performed in a state of distraction-free concentration that push cognitive capabilities to their limit.', sectionRef: 'What Is Deep Work?' },
    { question: 'What is "attention residue"?', options: ['The mental fatigue from long focus sessions', 'Part of your attention staying on a prior task when switching', 'The memories formed during deep work', 'Focus ability that builds up over time'], correctIndex: 1, explanation: 'Attention residue: when you switch tasks, part of your attention stays on the old task, reducing quality on the new one.', sectionRef: 'Attention Residue' },
    { question: 'Which deep work philosophy does Newport himself use?', options: ['Monastic', 'Bimodal', 'Rhythmic', 'Journalistic'], correctIndex: 2, explanation: 'Newport uses the rhythmic philosophy — a fixed daily schedule of deep work, building it into a regular morning routine.', sectionRef: 'The Four Philosophies' },
    { question: 'What does Newport recommend to "drain the shallows"?', options: ['Sleep 9 hours per night', 'Schedule every minute of your workday', 'Avoid all meetings', 'Work from home permanently'], correctIndex: 1, explanation: 'Scheduling every minute forces deliberate choice about how time is spent, reducing the default drift into shallow work.', sectionRef: 'Drain the Shallows' },
    { question: 'The "Any-Benefit Mindset" is problematic because:', options: ['It leads to addiction to productivity tools', 'It ignores the costs of a tool if any benefit exists', 'It makes people work too hard', 'It prevents use of useful technologies'], correctIndex: 1, explanation: 'Any-benefit mindset: adopt a tool if it provides any benefit. Newport argues the craftsman mindset — only adopt tools whose benefits substantially outweigh costs — is better.', sectionRef: 'Quit Social Media' },
    { question: 'What is the "fixed schedule productivity" strategy?', options: ['Working only 8-hour days with no overtime', 'Setting an endpoint to your workday and protecting it', 'Scheduling tasks in fixed daily time blocks', 'Using a timer for every activity'], correctIndex: 1, explanation: 'Fixed schedule productivity: commit to a specific end time (e.g., 5:30 PM), then work backward to figure out what actually needs to get done.', sectionRef: 'Fixed Schedule Productivity' },
    { question: 'Why does Newport argue boredom is important?', options: ['Boredom triggers creativity', 'Tolerating boredom builds the capacity to focus', 'Boredom signals you need a break', 'Boredom reduces anxiety during deep work'], correctIndex: 1, explanation: 'If you seek stimulation at every moment of boredom, you train your brain to need stimulation — undermining your ability to do deep work.', sectionRef: 'Embrace Boredom' },
    { question: 'What distinguishes the "craftsman mindset" from the passion mindset?', options: ['Craftsmen love their work more', 'Craftsmen focus on what value they offer the world, not what work offers them', 'Craftsmen specialize in one skill only', 'Craftsmen never switch careers'], correctIndex: 1, explanation: 'Craftsman mindset: what can I offer the world? Passion mindset: what can the world offer me? Craftsmen develop rare skills that create passion organically.', sectionRef: 'The Craftsman Mindset' },
    { question: 'Why does Newport recommend "productive meditation"?', options: ['It improves sleep quality', 'It lets you solve professional problems during physical activity', 'It replaces traditional meditation', 'It helps with work-life balance'], correctIndex: 1, explanation: 'Productive meditation: during physical activity (walking, jogging), focus your attention on a professional problem. Trains concentration while being physically active.', sectionRef: 'Productive Meditation' },
    { question: 'What is the "depth philosophy" of the journalist approach?', options: ['Writing deeply researched articles', 'Shifting into deep work mode whenever time permits', 'Setting deep work sessions between interviews', 'Working late at night when others are asleep'], correctIndex: 1, explanation: 'Journalistic philosophy: like a journalist who can enter deep focus on deadline whenever opportunity arises — requires practiced ability to switch modes quickly.', sectionRef: 'The Four Philosophies' },
  ],
  'rich-dad-poor-dad': [
    { question: 'How does Rich Dad define an "asset"?', options: ['Anything you own', 'Something that puts money in your pocket', 'Your primary residence', 'Your education and skills'], correctIndex: 1, explanation: 'Rich Dad\'s definition: an asset puts money IN your pocket regardless of whether you work. A house that costs you monthly is a liability, not an asset.', sectionRef: 'Assets vs. Liabilities' },
    { question: 'What is the "Rat Race"?', options: ['Competing with coworkers for promotion', 'The cycle of working, spending, and needing more money', 'Running a business in a competitive market', 'Getting a college degree to get a job'], correctIndex: 1, explanation: 'The Rat Race: work for employer → pay taxes → buy things → need more money → work harder → repeat. Most middle-class people are trapped in it.', sectionRef: 'The Rat Race' },
    { question: 'The "Cash Flow Quadrant" has which four categories?', options: ['Employee, Self-Employed, Business Owner, Investor', 'Worker, Manager, Owner, Stockholder', 'Employee, Freelancer, Entrepreneur, Capitalist', 'Saver, Spender, Investor, Consumer'], correctIndex: 0, explanation: 'E (Employee), S (Self-Employed), B (Business Owner), I (Investor). Rich Dad says B and I provide financial freedom; E and S keep you dependent on your time.', sectionRef: 'The Cash Flow Quadrant' },
    { question: 'What does Rich Dad say about your house?', options: ['It is your most important asset', 'It can be an asset or liability depending on how you use it', 'It is usually a liability', 'It always appreciates in value'], correctIndex: 2, explanation: 'Rich Dad controversially says your house is a liability if it costs you money every month (mortgage, maintenance, taxes). Real assets generate income.', sectionRef: 'Your House Is Not an Asset' },
    { question: 'What is "financial intelligence"?', options: ['Knowing how to file taxes', 'Knowledge of accounting, investing, markets, and law', 'Getting a finance degree', 'Understanding stock market charts'], correctIndex: 1, explanation: 'Financial intelligence: accounting (read numbers), investing (make money work), markets (supply/demand), law (tax advantages and protection).', sectionRef: 'Financial Intelligence' },
    { question: 'What are the three types of income?', options: ['Salary, bonus, pension', 'Earned, portfolio, passive', 'Active, semi-active, passive', 'Work, savings, investment'], correctIndex: 1, explanation: 'Earned income (wages), portfolio income (capital gains), passive income (cash flow from assets). Rich Dad focuses on passive and portfolio income.', sectionRef: 'Three Types of Income' },
    { question: 'What does Rich Dad mean by "mind your own business"?', options: ['Don\'t interfere in others\' affairs', 'Build your asset column outside of your job', 'Start your own company', 'Keep your finances private'], correctIndex: 1, explanation: 'Mind your own business: your real business is building your asset column — investments, real estate, businesses — regardless of your day job.', sectionRef: 'Mind Your Own Business' },
    { question: 'What is the primary reason the rich get richer?', options: ['They start with more money', 'They take bigger risks', 'Their assets generate income that buys more assets', 'They work at higher-paying jobs'], correctIndex: 2, explanation: 'The rich get richer because their assets generate income, which they use to buy more assets. Wealth builds on itself — the opposite of trading time for money.', sectionRef: 'Why the Rich Get Richer' },
    { question: 'What does Rich Dad say about taxes?', options: ['Always pay minimum taxes legally', 'Corporations pay taxes after expenses; employees pay before', 'Tax avoidance is unethical', 'Taxes are unavoidable for everyone equally'], correctIndex: 1, explanation: 'Corporations earn → spend → pay taxes on what\'s left. Employees earn → pay taxes → spend what\'s left. The rich use corporations to legally reduce tax burden.', sectionRef: 'The Tax Advantage' },
    { question: 'What is Rich Dad\'s view on "working for money"?', options: ['It is the most reliable path to wealth', 'It is necessary early in life', 'The poor and middle class work for money; the rich have money work for them', 'Working hard always leads to wealth'], correctIndex: 2, explanation: 'The central thesis: "The poor and middle class work for money. The rich have money work for them." Financial education creates the shift.', sectionRef: 'The Core Lesson' },
  ],
  'the-psychology-of-money': [
    { question: 'What is Morgan Housel\'s key claim about financial success?', options: ['It requires high IQ', 'It depends more on behavior than intelligence', 'It is mostly about choosing the right investments', 'It requires starting early with large capital'], correctIndex: 1, explanation: 'The central thesis: doing well with money has little to do with intelligence and a lot to do with how you behave. Behavior > knowledge.', sectionRef: 'The Core Message' },
    { question: 'What does "tail-end" thinking mean in investing?', options: ['Focusing on the last 10% of gains', 'A small number of events drive most outcomes', 'Holding investments until the end', 'Avoiding losses at all costs'], correctIndex: 1, explanation: 'In long-term investing, a handful of exceptional years (or stocks) account for most returns. Expect many failures; the winners make up for everything.', sectionRef: 'Tails, You Win' },
    { question: 'What does Housel say is the real value of wealth?', options: ['Luxury and status', 'Ability to control your time', 'Security in retirement', 'Freedom from employment'], correctIndex: 1, explanation: 'The highest form of wealth is the ability to wake up every morning and do whatever you want. Time control — not consumption — is true wealth.', sectionRef: 'Freedom' },
    { question: 'What is "goalpost-moving" in wealth psychology?', options: ['Changing your savings target as you age', 'The problem of wanting more as you earn more', 'Tracking net worth milestones', 'Adjusting for inflation'], correctIndex: 1, explanation: 'Goalpost-moving: when you achieve wealth, you compare upward and the goal moves. Without defining "enough," satisfaction is perpetually out of reach.', sectionRef: 'Never Enough' },
    { question: 'Why should you "save just to save"?', options: ['Compound interest requires consistent saving', 'Saving builds optionality for an unknowable future', 'Savings accounts earn guaranteed returns', 'Emergency funds must cover 6 months of expenses'], correctIndex: 1, explanation: 'Saving without a specific goal builds flexibility and optionality. Life\'s biggest opportunities are often unexpected — capital lets you seize them.', sectionRef: 'Save Money' },
    { question: 'What does Housel mean by "reasonable vs. rational" financial decisions?', options: ['Math-based vs. gut-based decisions', 'Good-enough decisions you can stick to vs. optimal ones you cannot', 'Short-term vs. long-term thinking', 'Emotional vs. logical thinking'], correctIndex: 1, explanation: 'Purely rational decisions (e.g., 100% stocks always) may be mathematically optimal but emotionally unsustainable. Reasonable decisions you can follow beat perfect ones you abandon.', sectionRef: 'Reasonable vs. Rational' },
    { question: 'What role does luck play in wealth according to Housel?', options: ['None — wealth is purely skill', 'It\'s more important than skill for most people', 'Luck and risk are inseparable parts of every financial outcome', 'Luck only matters in early stages'], correctIndex: 2, explanation: 'Luck and risk are siblings — both exist in every outcome. Acknowledging this creates humility and prevents over-attributing success to personal genius.', sectionRef: 'Luck and Risk' },
    { question: 'What is the "Paradox of Wealth"?', options: ['Rich people are often unhappy', 'Flashy wealth signals insecurity, not success', 'Wealth makes you want more', 'The wealthy work more hours than the poor'], correctIndex: 1, explanation: 'Driving a luxury car signals "I have money" — but other people see the car and think about how they\'d look with that car, not admiring you. Wealth is often what you don\'t see.', sectionRef: 'The Paradox of Wealth' },
    { question: 'What is "room for error" in financial planning?', options: ['Accepting that you will make mistakes', 'Building buffers so surprises don\'t ruin you', 'Having an emergency fund', 'Diversifying investments'], correctIndex: 1, explanation: 'Room for error: the future is uncertain, so plan with buffers. The goal is to survive long enough for compounding to work. Margin of safety > optimization.', sectionRef: 'Room for Error' },
    { question: 'Why does Housel say compounding is so hard to intuitively grasp?', options: ['The math is too complex', 'Results are invisible for long periods, then seem sudden', 'It only works for the very wealthy', 'Inflation erodes compound gains'], correctIndex: 1, explanation: 'Compounding takes years to show results, then accelerates dramatically. Warren Buffett\'s wealth came overwhelmingly from the last 20 years of his investing career — time, not genius.', sectionRef: 'Compounding' },
  ],
  'cant-hurt-me': [
    { question: 'What is Goggins\' "40% Rule"?', options: ['You need 40% more sleep than you think', 'When your mind says stop, you\'re only at 40% of your capacity', 'Give 40% effort to hard things', 'Complete 40 hard things per year'], correctIndex: 1, explanation: 'The 40% rule: when your mind and body say they\'re done, you\'ve only used about 40% of your actual capacity. The rest is mental barriers.', sectionRef: 'The 40% Rule' },
    { question: 'What is the "Cookie Jar Method"?', options: ['Rewarding yourself with treats for completing goals', 'Using past hard wins as mental fuel when struggling', 'Keeping a list of daily habits', 'Collecting motivational quotes'], correctIndex: 1, explanation: 'Cookie Jar: recall past hard things you\'ve survived and achieved. Mentally reach into that jar for fuel when facing a new challenge.', sectionRef: 'The Cookie Jar' },
    { question: 'What does Goggins mean by "callousing the mind"?', options: ['Being emotionally detached', 'Deliberately doing hard things to build mental resilience', 'Meditating daily to reduce stress', 'Ignoring negative thoughts'], correctIndex: 1, explanation: 'Just as hands callous with manual labor, the mind toughens with repeated exposure to discomfort. Seek difficulty intentionally.', sectionRef: 'Callousing the Mind' },
    { question: 'What was Goggins\' weight when he decided to become a Navy SEAL?', options: ['175 pounds', '197 pounds', '246 pounds', '285 pounds'], correctIndex: 2, explanation: 'Goggins was 297 pounds when he set his mind on becoming a SEAL. He lost 106 pounds in three months through extreme discipline.', sectionRef: 'The Starting Point' },
    { question: 'What is the "Accountability Mirror"?', options: ['A daily journal habit', 'Looking in the mirror and being brutally honest about your excuses', 'Tracking your weekly goals', 'Having a partner hold you accountable'], correctIndex: 1, explanation: 'Accountability mirror: every day, face yourself in the mirror. Write your goals on sticky notes. Be brutally honest about where you\'re failing.', sectionRef: 'Accountability Mirror' },
    { question: 'What happened to Goggins during Hell Week that tested his resolve?', options: ['He broke his arm', 'He developed rhabdomyolysis and fractured both shins', 'He nearly drowned', 'He was disqualified and had to restart'], correctIndex: 1, explanation: 'Goggins developed rhabdomyolysis, fractured his shins, and was medically pulled out. He went through Hell Week three times total to prove he could do it.', sectionRef: 'Hell Week' },
    { question: 'What was the impact of Goggins\' childhood on his mindset?', options: ['His wealthy upbringing made him complacent', 'He grew up in severe poverty and abuse, which he later used as fuel', 'A supportive family instilled confidence in him', 'He had no major hardships in childhood'], correctIndex: 1, explanation: 'Goggins grew up in an abusive home, faced racism, had a severe learning disability, and lived in poverty. He used every hardship as motivation rather than excuse.', sectionRef: 'Childhood Trauma' },
    { question: 'How does Goggins define "uncommon amongst uncommon"?', options: ['Being the best in your field', 'Continuing to push beyond what even exceptional people accept as their limit', 'Achieving all your goals', 'Training harder than your peers'], correctIndex: 1, explanation: 'Even among elite performers (SEALs, ultramarathon runners), most stop at a comfortable limit. Being uncommon amongst uncommon means going beyond what even elites accept.', sectionRef: 'Uncommon Amongst Uncommon' },
    { question: 'What does the "Taking Souls" concept mean?', options: ['Dominating others competitively', 'Using your performance to break someone\'s will to push you', 'Ignoring your competition', 'Studying your competitors weaknesses'], correctIndex: 1, explanation: '"Taking souls": when someone tries to break you, use your performance to shatter their belief that they can. Your discipline and effort become a weapon against those who count you out.', sectionRef: 'Taking Souls' },
    { question: 'What was the Navy SEAL ethos Goggins lived by?', options: ['Be first, be fast, be fearless', 'The only easy day was yesterday', 'Pain is just weakness leaving the body', 'Failure is not an option'], correctIndex: 1, explanation: '"The only easy day was yesterday" — every day gets harder, and you must embrace that. This Navy SEAL motto captures Goggins\' philosophy of endless forward motion.', sectionRef: 'The Navy SEAL Ethos' },
  ],
  'the-lean-startup': [
    { question: 'What is the Build-Measure-Learn feedback loop?', options: ['Design → Test → Launch', 'Build MVP → Measure key metrics → Learn and pivot or persevere', 'Plan → Execute → Review → Repeat', 'Ideate → Build → Ship → Scale'], correctIndex: 1, explanation: 'The core Lean Startup engine: Build (minimum viable product) → Measure (real customer data) → Learn (what to do next). Minimize loop time.', sectionRef: 'Build-Measure-Learn' },
    { question: 'What is a "pivot"?', options: ['Changing your pricing strategy', 'A structured course correction testing a new fundamental hypothesis', 'Moving to a new target market', 'Updating product features based on feedback'], correctIndex: 1, explanation: 'A pivot is not just any change — it\'s a fundamental shift in strategy while preserving learned insights. Examples: zoom-in pivot, customer segment pivot, technology pivot.', sectionRef: 'Pivot or Persevere' },
    { question: 'What is "validated learning"?', options: ['Getting expert feedback on your business plan', 'Learning backed by real customer data from experiments', 'Taking business courses', 'Learning from failed competitors'], correctIndex: 1, explanation: 'Validated learning: demonstrating empirically what you\'ve learned — from real customers, not assumptions. It\'s the true unit of progress for a startup.', sectionRef: 'Validated Learning' },
    { question: 'What is the difference between vanity and actionable metrics?', options: ['Vanity metrics are external; actionable are internal', 'Vanity metrics feel good but don\'t drive decisions; actionable metrics tie to specific actions', 'Vanity metrics are about customers; actionable are financial', 'There is no meaningful difference'], correctIndex: 1, explanation: 'Vanity metrics (total signups, page views) make you feel good. Actionable metrics (conversion rate, retention) connect to specific actions you can take to improve.', sectionRef: 'Vanity vs. Actionable Metrics' },
    { question: 'What is an MVP?', options: ['The most valuable product in your lineup', 'The minimum version of a product that enables maximum learning', 'A product with minimum features for minimum cost', 'The first version of a product before it\'s ready'], correctIndex: 1, explanation: 'MVP: the version of a new product that allows collection of maximum validated learning with the least effort. Not minimum quality — minimum to enable learning.', sectionRef: 'The Minimum Viable Product' },
    { question: 'What is "innovation accounting"?', options: ['Creative bookkeeping for startups', 'A framework to measure if a startup is making real progress', 'Tracking cost savings from lean methods', 'Accounting for R&D tax credits'], correctIndex: 1, explanation: 'Innovation accounting: an alternative to traditional P&L. Track: baseline metrics → tune toward ideal → decide to pivot or persevere. Holds teams accountable for real learning.', sectionRef: 'Innovation Accounting' },
    { question: 'What is the "Five Whys" technique in Lean Startup?', options: ['Asking customers five questions about their problems', 'Asking "why" five times to find the root cause of a problem', 'Five questions to validate a business hypothesis', 'Five reasons why a product should exist'], correctIndex: 1, explanation: 'Five Whys: ask "why" five times to trace the root cause of any problem. A surface issue (website down) often has a deeper root (no deployment process). Fix the root, not the symptom.', sectionRef: 'Five Whys' },
    { question: 'What does Ries mean by "just do it" being wrong for startups?', options: ['Startups need more planning than established companies', 'Acting without measurement creates waste and fake progress', 'Speed should be sacrificed for quality', 'Startups should test ideas in focus groups first'], correctIndex: 1, explanation: '"Just do it" without a feedback loop creates waste — building features no one uses, spending on acquisition before product-market fit. Learning must come first.', sectionRef: 'The Big Idea' },
    { question: 'What is "customer development"?', options: ['A training program for customer service reps', 'The process of getting out of the building to test assumptions with real customers', 'Developing a loyal customer base', 'Customer journey mapping'], correctIndex: 1, explanation: 'Customer development: Steve Blank\'s method that Lean Startup builds on — get out of the building and talk to real customers before building anything.', sectionRef: 'Customer Development' },
    { question: 'What is "sustainable growth" according to Ries?', options: ['Growth funded without outside investment', 'Growth that comes from actions of past customers, not one-time campaigns', 'Growth at a steady, manageable pace', 'Carbon-neutral business operations'], correctIndex: 1, explanation: 'Sustainable growth: comes from three engines — sticky (retention), viral (word of mouth), paid (customer acquisition value > cost). Powered by existing customer behavior, not campaigns.', sectionRef: 'Engines of Growth' },
  ],
  'principles': [
    { question: 'What is Ray Dalio\'s most cited equation?', options: ['Revenue - Costs = Profit', 'Pain + Reflection = Progress', 'Work + Talent = Success', 'Discipline × Time = Results'], correctIndex: 1, explanation: '"Pain + Reflection = Progress." Without reflecting on painful failures, you just suffer. With reflection, each failure becomes a lesson that compounds into wisdom.', sectionRef: 'Embracing Reality' },
    { question: 'What is Bridgewater\'s practice of "radical transparency"?', options: ['Publishing all financials publicly', 'Recording all meetings, challenging all ideas regardless of hierarchy', 'Having no employee hierarchy', 'Sharing salaries across the company'], correctIndex: 1, explanation: 'Radical transparency at Bridgewater: all meetings recorded, all decisions logged, all mistakes examined publicly. Accelerates learning; requires emotional maturity.', sectionRef: 'Radical Transparency' },
    { question: 'What is an "idea meritocracy"?', options: ['A system where the smartest person wins', 'A system where the best ideas win regardless of who proposes them', 'Democracy applied to business decisions', 'Crowdsourcing decisions from all employees'], correctIndex: 1, explanation: 'Idea meritocracy: judge ideas on quality, not on the rank of the person proposing them. Requires radical transparency and algorithmic decision-making.', sectionRef: 'Idea Meritocracy' },
    { question: 'What does Dalio mean by "going to the higher level"?', options: ['Getting promoted', 'Stepping outside your current situation to see it objectively', 'Thinking about long-term goals', 'Consulting more senior advisors'], correctIndex: 1, explanation: 'Going to the higher level: seeing your situation as an observer would — removing ego and emotion. What looks painful up close often makes sense at a higher level.', sectionRef: 'The Higher Level' },
    { question: 'What is Dalio\'s "5-Step Process"?', options: ['Think, Plan, Act, Review, Improve', 'Goals → Problems → Diagnose → Design → Execute', 'Dream → Believe → Act → Persist → Succeed', 'Research → Hypothesize → Test → Measure → Scale'], correctIndex: 1, explanation: 'The 5-Step Process: 1. Set goals, 2. Identify problems, 3. Diagnose root causes, 4. Design solutions, 5. Execute. Loop through constantly to achieve goals.', sectionRef: 'The 5-Step Process' },
    { question: 'What is the "Two-You" problem Dalio describes?', options: ['Having two contradictory goals', 'The conflict between your emotional self and your rational self', 'Working for two different priorities', 'The gap between who you are and who you want to be'], correctIndex: 1, explanation: 'The two-you problem: your logical, higher-level you vs. your emotional, lower-level you. Most bad decisions come from the lower-level you taking over. Learn to recognize which one is speaking.', sectionRef: 'The Two-You Problem' },
    { question: 'What is "believability-weighted decision making"?', options: ['Trusting only people with proven track records', 'Weighting opinions by the credibility of the person on that specific topic', 'Making decisions based on data only', 'Voting on decisions democratically'], correctIndex: 1, explanation: 'Not all opinions are equal. Weight input by the person\'s relevant track record. A portfolio manager\'s view on markets counts more than a marketer\'s view — and vice versa.', sectionRef: 'Believability-Weighted Decisions' },
    { question: 'What does "radical open-mindedness" require?', options: ['Agreeing with everyone', 'Being willing to genuinely reconsider your own views when challenged', 'Never taking a strong position', 'Consulting others before every decision'], correctIndex: 1, explanation: 'Radical open-mindedness: the ability to genuinely hear and consider other views without the ego barrier. The goal is not to be right — it\'s to find the best answer.', sectionRef: 'Radical Open-Mindedness' },
    { question: 'What is the role of "algorithms" at Bridgewater?', options: ['Automated trading systems', 'Systematizing successful decision-making principles into repeatable processes', 'AI that makes investment decisions', 'Software that tracks employee performance'], correctIndex: 1, explanation: 'Dalio systematizes good judgment into algorithms — written principles that can be applied consistently regardless of emotion, bias, or who is in the room.', sectionRef: 'Principles as Algorithms' },
    { question: 'What does Dalio mean by "evolving the machine"?', options: ['Upgrading Bridgewater\'s technology', 'Constantly improving your systems and yourself based on results', 'Automating business processes', 'Building a team that runs without you'], correctIndex: 1, explanation: 'Evolving the machine: see yourself and your organization as machines that can always be improved. Diagnose outcomes, adjust the machine, evolve continuously.', sectionRef: 'Evolving the Machine' },
  ],
  'essentialism': [
    { question: 'What is the core philosophy of Essentialism?', options: ['Minimalism — own less stuff', '"Less but better" — the disciplined pursuit of less', 'Efficiency — do more in less time', 'Simplicity — remove complexity from systems'], correctIndex: 1, explanation: 'Essentialism: "less but better." Doing only the things that absolutely matter, and doing them with excellence. Not minimalism — deliberate focus on the vital few.', sectionRef: 'What Is Essentialism?' },
    { question: 'What is the "Hell Yeah or No" rule?', options: ['Only commit to things that excite you completely', 'Say yes only to things you are 100% certain about', 'Reject all obligations unless they are truly essential', 'Use enthusiasm as a filter for all decisions'], correctIndex: 0, explanation: '"Hell yeah or no": if an opportunity doesn\'t make you say "hell yeah!", say no. When you say yes to everything, you can give nothing your full effort.', sectionRef: 'Hell Yeah or No' },
    { question: 'What does the Essentialist do with opportunities that are merely "good"?', options: ['Accept them to build relationships', 'Decline them — only great opportunities make the cut', 'Delegate them to others', 'Delay the decision until more information is available'], correctIndex: 1, explanation: 'Essentialists say no to "good" opportunities to preserve capacity for "great" ones. Saying yes to the nonessential means saying no to the essential.', sectionRef: 'The Essentialist Mindset' },
    { question: 'What is "the sunk-cost trap" in essentialism?', options: ['Throwing good money after bad investments', 'Continuing a commitment because of past investment, not future value', 'Undervaluing current assets', 'Ignoring opportunity costs'], correctIndex: 1, explanation: 'The sunk-cost trap: staying on a bad path because you\'ve already invested time, money, or effort. Essentialists ask: "If I didn\'t already have this, how much would I pay to start it?" If less, let it go.', sectionRef: 'The Sunk-Cost Trap' },
    { question: 'What is the Essentialist approach to "protecting the asset"?', options: ['Buying insurance for valuable possessions', 'Investing in your own health, sleep, and renewal as a priority', 'Protecting intellectual property', 'Securing your financial assets'], correctIndex: 1, explanation: '"The asset" is you. Sleep, play, and renewal aren\'t luxuries — they\'re what enables peak performance. Essentialists invest in themselves first.', sectionRef: 'Protect the Asset' },
    { question: 'What is the "Explore, Eliminate, Execute" framework?', options: ['Research → Delete → Implement', 'Think broadly → Cut ruthlessly → Focus energy', 'Plan → Remove obstacles → Take action', 'Expand vision → Narrow focus → Complete projects'], correctIndex: 1, explanation: 'Explore: scan widely to identify what truly matters. Eliminate: ruthlessly cut everything that doesn\'t. Execute: put focused energy into the vital few. This is the Essentialist cycle.', sectionRef: 'The Essentialist System' },
    { question: 'What does McKeown say about "clarity of purpose"?', options: ['Clear goals help you stay motivated', 'Clarity about what\'s essential makes 1,000 decisions automatically', 'Purpose drives passion', 'Clarity of purpose requires a written mission statement'], correctIndex: 1, explanation: 'When you have a clear essential intent, it makes a thousand daily decisions automatically. You don\'t have to decide — you already know what to do because you know what matters most.', sectionRef: 'Clarity of Purpose' },
    { question: 'What is the "Nonessentialist" trap?', options: ['Procrastinating on important tasks', 'Trying to do everything, resulting in making no meaningful contribution', 'Focusing on cost reduction over value creation', 'Avoiding difficult conversations'], correctIndex: 1, explanation: 'The nonessentialist says yes to every request, tries to do everything, and ends up being spread thin — doing many things but none of them well.', sectionRef: 'The Nonessentialist Trap' },
    { question: 'What is "effortless execution" in Essentialism?', options: ['Making everything easy and comfortable', 'Removing obstacles so the essential path becomes the natural one', 'Automating all routine tasks', 'Working with maximum flow every day'], correctIndex: 1, explanation: 'Effortless execution: design your environment and systems so the right action is the easy action. Remove friction from the essential; add friction to the nonessential.', sectionRef: 'Effortless Execution' },
    { question: 'What does Essentialism say about multi-tasking?', options: ['It should be practiced with specific techniques', 'It is a myth — you can\'t truly focus on multiple priorities', 'It works well for shallow tasks', 'Modern tools make multi-tasking more effective'], correctIndex: 1, explanation: '"You can\'t have it all. You can have anything, but not everything." Multi-tasking divides focus. The Essentialist consciously chooses what to focus on and protects that choice.', sectionRef: 'On Multi-Tasking' },
  ],
  'the-compound-effect': [
    { question: 'What is the core principle of The Compound Effect?', options: ['High-risk, high-reward investments compound fastest', 'Small consistent actions done over time produce massive results', 'Success requires dramatic change', 'Compound interest is only financial'], correctIndex: 1, explanation: 'The core principle: small, smart choices + consistency + time = radical difference. No drama, no shortcuts — just the mathematics of compounding applied to habits.', sectionRef: 'The Compound Effect' },
    { question: 'What is "Big Mo" in The Compound Effect?', options: ['A big motivational goal', 'Momentum — once built, it powers continued forward motion', 'A major breakthrough moment', 'Monthly progress tracking'], correctIndex: 1, explanation: 'Big Mo = momentum. Like a flywheel, starting is hard. But once momentum builds, the compound effect feels effortless — progress accelerates naturally.', sectionRef: 'Momentum' },
    { question: 'What does Hardy say about "influences"?', options: ['Ignore outside influences and focus internally', 'Your inputs, associations, and environment compound like habits', 'Social media is the biggest negative influence', 'Mentors are the most important positive influence'], correctIndex: 1, explanation: 'Influences compound: the books you read, the people you spend time with, the media you consume — all shape who you become. Upgrade your inputs.', sectionRef: 'Influences' },
    { question: 'What story does Hardy use to illustrate the compound effect?', options: ['Three friends who all start at the same point but make slightly different choices', 'A farmer who plants different crops', 'A runner who trains differently from their competitors', 'An investor who uses three different strategies'], correctIndex: 0, explanation: 'Three friends: Brad stays the same, Scott makes slightly negative choices, Larry makes slightly positive choices. Over 18 months, the gap between Scott and Larry is enormous — from identical starting points.', sectionRef: 'The Three Friends Story' },
    { question: 'What is the first step of the Compound Effect?', options: ['Making a dramatic commitment', 'Identifying what small action you can do consistently', 'Tracking your choices', 'Finding a mentor'], correctIndex: 2, explanation: 'Tracking: you cannot improve what you don\'t measure. The simple act of tracking creates awareness and accountability that starts the compound effect.', sectionRef: 'Tracking Your Choices' },
    { question: 'What does Hardy say about your associations (people around you)?', options: ['You are the average of the five people you spend the most time with', 'Choose friends based on shared values only', 'Associations matter less than personal discipline', 'Online networks are more important than physical ones'], correctIndex: 0, explanation: 'You are the average of the five people you spend the most time with. Evaluate every key relationship: does this person lift you up or pull you down?', sectionRef: 'Associations' },
    { question: 'What is the "Ripple Effect" in The Compound Effect?', options: ['A negative action causing more negative actions', 'One choice causing a chain of related positive choices', 'Market movements affecting personal finances', 'How habits spread to family members'], correctIndex: 1, explanation: 'The ripple effect: one good choice sets off a chain of related good choices. Starting to exercise leads to better eating, better sleep, better work, better relationships.', sectionRef: 'The Ripple Effect' },
    { question: 'What is Hardy\'s view on "luck"?', options: ['Luck is random and can\'t be influenced', 'Luck = preparation + opportunity', 'Lucky people are simply in the right place at the right time', 'Luck matters less than hard work always'], correctIndex: 1, explanation: 'Luck = preparation + opportunity. The compound effect of consistent preparation means when opportunity appears, you\'re ready. What looks like luck is years of daily choices.', sectionRef: 'The Luck Factor' },
    { question: 'What does Hardy recommend tracking to start the compound effect?', options: ['Only your financial net worth', 'Every decision in three key areas of life', 'Just your daily habits', 'Only professional achievements'], correctIndex: 1, explanation: 'Track decisions in the three areas that matter most to you (financial, relationships, health). Awareness precedes change — you can\'t fix what you don\'t see.', sectionRef: 'Three Key Areas' },
    { question: 'What is the "Success Pattern"?', options: ['A morning routine formula', 'Consistent daily disciplines that reflect your values and goals', 'The habits of successful people to copy', 'A goal-setting system'], correctIndex: 1, explanation: 'Your success pattern is found in your daily choices. Every day you vote for the person you\'re becoming through consistent actions aligned with your values.', sectionRef: 'Your Success Pattern' },
  ],
  'mindset': [
    { question: 'What is the fundamental belief of the Fixed Mindset?', options: ['You can improve with effort', 'Intelligence and talent are fixed and unchangeable', 'Some people are born for success', 'Hard work is the key to everything'], correctIndex: 1, explanation: 'Fixed mindset: intelligence, talent, and character are carved in stone. Your qualities are fixed — and every situation is a test of how much you have.', sectionRef: 'The Two Mindsets' },
    { question: 'What is the fundamental belief of the Growth Mindset?', options: ['Everyone can become a genius', 'Abilities can be developed through dedication and hard work', 'Success is available to anyone who wants it enough', 'Effort always produces proportional results'], correctIndex: 1, explanation: 'Growth mindset: basic qualities can be cultivated through effort. Not that everyone is equal, but that everyone can grow through hard work and good strategies.', sectionRef: 'The Two Mindsets' },
    { question: 'How does praise affect a child\'s mindset according to Dweck\'s research?', options: ['Any positive praise builds confidence', 'Praising talent builds fixed mindset; praising effort builds growth mindset', 'Praise should be avoided as it creates dependency', 'Frequent praise increases academic performance'], correctIndex: 1, explanation: 'Dweck\'s research: children praised for being "smart" developed fixed mindsets and avoided challenges. Children praised for effort developed growth mindsets and embraced challenges.', sectionRef: 'The Power of Praise' },
    { question: 'What is the "Not Yet" concept?', options: ['Delaying difficult conversations', 'Replacing "I can\'t" with "I can\'t yet" to open a path forward', 'Setting goals without deadlines', 'Accepting imperfection in your work'], correctIndex: 1, explanation: '"Not yet" reframes failure as a point on a learning curve, not a permanent verdict. "I failed the test" becomes "I haven\'t mastered this yet."', sectionRef: 'The Power of Yet' },
    { question: 'What happens to fixed mindset people when they fail?', options: ['They become more motivated to prove themselves', 'They see it as proof of their lack of ability', 'They analyze what went wrong', 'They seek feedback and advice'], correctIndex: 1, explanation: 'Fixed mindset people interpret failure as proof they lack ability. They may hide their struggle, cheat, or look for someone else to blame rather than learn from the experience.', sectionRef: 'Responding to Failure' },
    { question: 'What is the "False Growth Mindset"?', options: ['Claiming to have growth mindset but not practicing it', 'Believing effort alone guarantees success', 'Growth mindset applied only to academic performance', 'Using growth language without making structural changes'], correctIndex: 0, explanation: 'False growth mindset: saying "I believe in growth" but still avoiding challenges, giving up when things get hard, or not taking feedback well. Growth mindset must be practiced, not just claimed.', sectionRef: 'The False Growth Mindset' },
    { question: 'How can leaders create growth mindset cultures?', options: ['By setting stretch goals', 'By rewarding process, effort, and learning — not just results', 'By hiring only growth-minded people', 'By creating competitive environments'], correctIndex: 1, explanation: 'Growth-mindset leaders: value learning, encourage risk-taking, celebrate effort and improvement, and see mistakes as information rather than failures to punish.', sectionRef: 'Growth Mindset in Organizations' },
    { question: 'What does Dweck say about geniuses and naturally talented people?', options: ['Natural talent always leads to greater success', 'Natural talent can create fixed mindset and limit potential', 'Geniuses always have growth mindsets', 'Talent matters more than effort in the long run'], correctIndex: 1, explanation: 'Being told you\'re naturally gifted can instill a fixed mindset — you stop working as hard to preserve your "natural genius" label. Many geniuses underperform their potential because of this.', sectionRef: 'The Tyranny of Now' },
    { question: 'What is the inner dialogue of a growth mindset person facing a challenge?', options: ['"Can I do this?"', '"This might be too hard for me"', '"This is a chance to learn and grow"', '"I\'ll try, but it might not work"'], correctIndex: 2, explanation: 'Growth mindset inner dialogue: "This is a challenge — what a chance to stretch and improve." The challenge itself is the reward, not just the outcome.', sectionRef: 'Inner Dialogue' },
    { question: 'Can someone with a fixed mindset change to a growth mindset?', options: ['No — mindset is itself fixed', 'Yes, with awareness and deliberate practice', 'Only if they change careers', 'Only in childhood'], correctIndex: 1, explanation: 'Yes — awareness is the first step. Notice when your fixed mindset voice speaks. Name it. Then choose a growth response. Mindset is changeable at any age.', sectionRef: 'Changing Your Mindset' },
  ],
  'start-with-why': [
    { question: 'What is the "Golden Circle"?', options: ['A framework for pricing products', 'Three concentric circles: Why, How, What — from inside out', 'A model for organizational structure', 'A leadership development program'], correctIndex: 1, explanation: 'The Golden Circle: Why (your purpose/cause), How (your values/process), What (your products/services). Inspiring leaders communicate from inside out — Why → How → What.', sectionRef: 'The Golden Circle' },
    { question: 'Why does Apple succeed beyond its products?', options: ['Superior technology', 'Clever marketing and advertising', 'Communicating a WHY — challenging the status quo — first', 'Celebrity endorsements'], correctIndex: 2, explanation: 'Apple\'s WHY: "We challenge the status quo." Everything they make serves that belief. People buy the belief, not the computer. Same WHY, different products (Mac, iPod, iPhone).', sectionRef: 'Apple\'s Golden Circle' },
    { question: 'What does the "Law of Diffusion of Innovation" say about mass adoption?', options: ['Products go viral naturally if good enough', 'To cross the chasm to the majority, you must first win 15-18% early adopters who share your beliefs', 'Mass market needs massive advertising', 'Price drops always trigger mass adoption'], correctIndex: 1, explanation: 'To tip into the early and late majority (the mass market), you must first win the 15-18% early adopters who believe what you believe — not just see value in your product.', sectionRef: 'Law of Diffusion of Innovation' },
    { question: 'What is the difference between manipulation and inspiration?', options: ['Manipulation is illegal; inspiration is not', 'Manipulation is short-term; inspiration creates lasting loyalty', 'Inspiration is louder than manipulation', 'Manipulation works better for B2B; inspiration for B2C'], correctIndex: 1, explanation: 'Manipulations (price, fear, peer pressure, promotions) work once but create no loyalty. Inspiration — shared beliefs — creates customers who become advocates and never leave.', sectionRef: 'Manipulation vs. Inspiration' },
    { question: 'What does Sinek mean by "The Celery Test"?', options: ['Testing if your product is healthy for users', 'Using your WHY to filter all decisions', 'Choosing the simplest approach to any problem', 'A framework for product testing'], correctIndex: 1, explanation: 'The Celery Test: a friend says "take celery AND M&Ms AND Oreos AND rice milk." Without clarity on your WHY, you take everything. With a clear WHY, you take only what aligns — just celery.', sectionRef: 'The Celery Test' },
    { question: 'What is a "trust fund" in the context of Start With Why?', options: ['A financial inheritance', 'The reservoir of trust built by consistent WHY-driven behavior', 'A savings account for the company', 'An employee benefit program'], correctIndex: 1, explanation: 'Every time you act in accordance with your WHY, you make a deposit in your trust fund. When you act against it, you make a withdrawal. Trust funds can go bankrupt through inconsistency.', sectionRef: 'The Trust Fund' },
    { question: 'Why do great leaders "start with why" when hiring?', options: ['To find candidates with the right skills', 'To find people who share their beliefs, not just their goals', 'To set salary expectations clearly', 'To explain the company\'s competitive advantages'], correctIndex: 1, explanation: 'Hiring people who share your WHY creates intrinsic motivation and loyalty. People don\'t go to work for a company — they go to work for a cause. WHY-aligned employees need less management.', sectionRef: 'Why and Hiring' },
    { question: 'What happened to companies like Walmart or Dell when they started making decisions based only on WHAT?', options: ['They became more profitable', 'They lost trust and loyalty as their WHY became unclear', 'They achieved market dominance', 'They became more innovative'], correctIndex: 1, explanation: 'When companies forget their WHY and optimize purely for WHAT (profit, market share), they lose the cultural clarity that made them special. Employees and customers feel the inauthenticity.', sectionRef: 'When Companies Lose Their WHY' },
    { question: 'What is the role of "HOW" people vs. "WHY" people in an organization?', options: ['HOW people are more important', 'WHY people inspire; HOW people build the systems that realize the vision', 'WHY people are strategists; HOW people are operators', 'They serve the same function'], correctIndex: 1, explanation: 'WHY people (visionaries) often struggle to build repeatable systems. HOW people complement them by building the structures that actually deliver on the vision. Both are necessary.', sectionRef: 'WHY and HOW Guys' },
    { question: 'What does Sinek say is the cause of the "split" — when a company\'s external success diverges from its internal why?', options: ['Rapid growth and scaling', 'Leadership transition and the new leader\'s focus on short-term results', 'Market competition forcing new strategies', 'Board pressure for quarterly earnings'], correctIndex: 1, explanation: 'The Split: often happens when a visionary founder leaves and a result-oriented leader takes over. The company keeps the WHAT but loses the WHY — leading to short-term thinking and declining culture.', sectionRef: 'The Split' },
  ],
  'the-7-habits': [
    { question: 'What is the "Character Ethic" that Covey says is the foundation of real effectiveness?', options: ['Personality, charm, and social skills', 'Fundamental principles like integrity, humility, and courage', 'Goal-setting and time management skills', 'Networking and relationship building'], correctIndex: 1, explanation: 'The Character Ethic: building success on fundamental principles — integrity, humility, fidelity, courage, justice. Contrasted with the Personality Ethic (surface-level techniques).', sectionRef: 'Character vs. Personality Ethic' },
    { question: 'What does Habit 1 "Be Proactive" mean?', options: ['Take initiative and move fast', 'Between stimulus and response, choose your response — focus on what you control', 'Be aggressive in pursuing goals', 'Plan ahead for potential problems'], correctIndex: 1, explanation: 'Proactive: between every stimulus and response is your freedom to choose. Focus your energy on the Circle of Influence — what you can change — not the Circle of Concern.', sectionRef: 'Habit 1: Be Proactive' },
    { question: 'What does "Begin With the End in Mind" require?', options: ['Setting SMART goals', 'Writing a personal mission statement that defines your values and purpose', 'Planning projects from finish to start', 'Visualizing success before beginning'], correctIndex: 1, explanation: 'Begin with the end in mind: create a personal mission statement that defines who you want to be and what you want to do. All activity should flow from this mental/spiritual creation.', sectionRef: 'Habit 2: Begin With the End in Mind' },
    { question: 'What are the four quadrants of the Time Management Matrix?', options: ['Now, Soon, Later, Never', 'Important/Urgent, Important/Not Urgent, Not Important/Urgent, Not Important/Not Urgent', 'Work, Home, Health, Social', 'Daily, Weekly, Monthly, Annual'], correctIndex: 1, explanation: 'Quadrant I: crises (important/urgent). Quadrant II: planning (important/not urgent) — where effective people focus. Quadrant III: interruptions. Quadrant IV: time-wasting.', sectionRef: 'Habit 3: Put First Things First' },
    { question: 'What is a "Win/Win" agreement?', options: ['Negotiating until both sides are equally unhappy', 'Seeking mutually beneficial solutions in all interactions', 'Making sure you get the best deal', 'Compromising your needs to maintain a relationship'], correctIndex: 1, explanation: 'Think Win/Win: seek solutions where both parties benefit. Not Win/Lose (I win, you lose) or Lose/Win (I sacrifice to keep peace) — truly believing that there is enough for everyone.', sectionRef: 'Habit 4: Think Win/Win' },
    { question: 'What does "Seek First to Understand, Then to Be Understood" mean in practice?', options: ['Research topics before sharing opinions', 'Listen with the intent to understand, not just to reply', 'Gather data before making decisions', 'Ask questions before giving answers'], correctIndex: 1, explanation: 'Empathic listening: most people listen with the intent to reply, not understand. Genuine empathy — understanding the other person\'s frame of reference — creates trust and effective communication.', sectionRef: 'Habit 5: Seek First to Understand' },
    { question: 'What is "Synergy" (Habit 6)?', options: ['Working efficiently as a team', 'The whole being greater than the sum of its parts', 'Agreeing on shared goals', 'Eliminating team conflict'], correctIndex: 1, explanation: 'Synergy: when two people with different perspectives combine, they create something neither could create alone. Creative cooperation produces solutions better than any individual could develop.', sectionRef: 'Habit 6: Synergize' },
    { question: 'What is "Sharpening the Saw" (Habit 7)?', options: ['Improving your skills in your field', 'Continually renewing yourself in four dimensions: physical, mental, social/emotional, spiritual', 'Taking regular vacations', 'Reading books to stay current'], correctIndex: 1, explanation: 'Sharpen the Saw: the habit that enables all others. Renew in four dimensions: physical (exercise, nutrition), mental (reading, learning), social/emotional (relationships), spiritual (values, meditation).', sectionRef: 'Habit 7: Sharpen the Saw' },
    { question: 'What does Covey mean by the "Emotional Bank Account"?', options: ['Saving money for emotional purchases', 'The trust built up in relationships through deposits (kindness, honesty) and withdrawals (rudeness, breaking promises)', 'Emotional intelligence as a career asset', 'A budget for social activities'], correctIndex: 1, explanation: 'Emotional Bank Account: you make deposits (keeping promises, showing kindness) and withdrawals (rudeness, dishonesty) in every relationship. High balance = high trust.', sectionRef: 'The Emotional Bank Account' },
    { question: 'What is the "P/PC Balance"?', options: ['Performance and Potential Capacity', 'Production and Production Capability balance', 'Professional and Personal life balance', 'Planning and Control Balance'], correctIndex: 1, explanation: 'P/PC Balance: Production (getting results) vs. Production Capability (maintaining your capacity to produce). Overwork kills the goose (you) that lays the golden eggs.', sectionRef: 'The P/PC Balance' },
  ],
  'the-almanack-of-naval-ravikant': [
    { question: 'What is "specific knowledge" according to Naval?', options: ['Deep expertise in a technical field', 'Knowledge you cannot be trained for — found at the intersection of passion, curiosity, and talent', 'Specialized academic knowledge', 'Industry-specific skills acquired over time'], correctIndex: 1, explanation: 'Specific knowledge: what feels like play to you but looks like work to others. It can\'t be taught — it\'s the unique combination of your curiosity, passion, and skills.', sectionRef: 'Specific Knowledge' },
    { question: 'What are the three types of leverage Naval describes?', options: ['Money, Network, Skills', 'Labor, Capital, Products (code/media)', 'Assets, Relationships, Expertise', 'Time, Money, Effort'], correctIndex: 1, explanation: 'The three levers: 1. Labor (people working for you), 2. Capital (money working for you), 3. Products with no marginal cost of replication — code and media. The third is new and democratized.', sectionRef: 'The Three Types of Leverage' },
    { question: 'What does Naval mean by "accountability"?', options: ['Being responsible to your employer', 'Taking on business risk under your own name to gain credit and leverage', 'Tracking your own habits and goals', 'Answering to investors and stakeholders'], correctIndex: 1, explanation: 'Accountability: put your name on your work and take ownership of outcomes. Without accountability (which involves risk), there is no outsized credit. Risk = leverage.', sectionRef: 'Accountability' },
    { question: 'How does Naval define "wealth" vs. "money"?', options: ['Wealth is more than money', 'Wealth is assets that earn while you sleep; money is how you transfer time and status', 'Wealth is net worth; money is liquid cash', 'There is no meaningful difference'], correctIndex: 1, explanation: 'Wealth = assets (businesses, code, media) that earn for you while you sleep. Money = medium of exchange. Status = your rank in social hierarchy. Pursue wealth, not just money or status.', sectionRef: 'Wealth vs. Money vs. Status' },
    { question: 'What is the role of "code and media" in Naval\'s wealth framework?', options: ['Entertainment and distraction tools', 'Permissionless leverage available to anyone — they scale infinitely with no marginal cost', 'Credentials for the modern economy', 'Tools for building personal brands'], correctIndex: 1, explanation: 'Code and media require no permission, no employees, and no capital to scale. One person can reach millions. This is the democratization of leverage that didn\'t exist before the internet.', sectionRef: 'Code and Media' },
    { question: 'What does Naval say about the relationship between reading and success?', options: ['Reading is overrated for entrepreneurs', 'Read what you love — curiosity-driven reading compounds into genuine expertise', 'Read only industry-specific books', 'Read widely but not deeply'], correctIndex: 1, explanation: 'Read what genuinely interests you, not what you think you should read. Curiosity-driven reading produces the unusual knowledge combinations that create real leverage.', sectionRef: 'Reading and Learning' },
    { question: 'What is Naval\'s view on "working hard" vs. "working smart"?', options: ['Working smart always beats working hard', 'Work hard on the right things — judgment about what to work on matters most', 'Physical effort is underrated in the knowledge economy', 'Outsource everything you can'], correctIndex: 1, explanation: 'Hard work matters — but first, have judgment about what deserves your effort. Hard work in the wrong direction compounds failure. Specific knowledge + judgment + leverage = outsized results.', sectionRef: 'Hard Work and Judgment' },
    { question: 'What does Naval say about finding happiness?', options: ['Happiness comes from achieving your goals', 'Happiness is your natural state when you remove what makes you unhappy', 'Happiness is found in relationships', 'Happiness is a skill requiring constant practice'], correctIndex: 1, explanation: 'Happiness is not something you pursue — it\'s the state that remains when you stop running from it. Remove the sources of unhappiness. It\'s a choice, not a reward.', sectionRef: 'Happiness' },
    { question: 'What is the "long game" Naval refers to?', options: ['Investing only in long-term financial instruments', 'Playing for long-term reputation and relationships, compounding trust over decades', 'Five-year business planning', 'Patience in career progression'], correctIndex: 1, explanation: 'Play the long game in everything: relationships, investments, career. Long-term thinking filters out short-term noise and aligns you with people who have skin in the game.', sectionRef: 'Playing the Long Game' },
    { question: 'What does Naval say about the "price" of success?', options: ['Success requires sacrificing health', 'You will pay a price for everything — choose consciously what price is worth paying', 'Success is free if you have the right strategy', 'The price of success is working 80 hours a week'], correctIndex: 1, explanation: 'Everything has a price. Success in business costs time with family. Fame costs privacy. Know the price before paying it. Most people pay the price and then complain they didn\'t know what it cost.', sectionRef: 'The Price of Success' },
  ],
  'zero-to-one': [
    { question: 'What does Thiel mean by "Zero to One"?', options: ['Starting from nothing', 'Creating something genuinely new (vertical progress) vs. copying what works (horizontal)', 'Moving from idea to execution', 'Going from 0 to 1 customers'], correctIndex: 1, explanation: 'Zero to One = vertical progress: creating something that hasn\'t existed before. One to N = horizontal progress: copying and scaling existing solutions. Real innovation only happens Zero to One.', sectionRef: 'Zero to One vs. One to N' },
    { question: 'What is Thiel\'s "contrarian question"?', options: ['What do competitors get wrong?', '"What important truth do very few people agree with you on?"', 'What will the world look like in 20 years?', 'Why has no one built this before?'], correctIndex: 1, explanation: '"What important truth do very few people agree with you on?" Great businesses are built on secrets — insights others haven\'t seen. If everyone agrees, there\'s no edge.', sectionRef: 'The Contrarian Question' },
    { question: 'Why does Thiel prefer monopolies over competition?', options: ['Monopolies have more cash to invest in R&D', 'Competition destroys profit; monopolies generate profit to fund innovation', 'Monopolies are better for consumers', 'Competition leads to quality decline'], correctIndex: 1, explanation: 'Competition destroys profits and forces everyone to be the same. Monopolies — companies so good no competitor can offer a close substitute — generate the profits that enable real innovation.', sectionRef: 'Competition Is for Losers' },
    { question: 'What are the four characteristics Thiel says define a monopoly?', options: ['Scale, Network, Brand, Capital', 'Proprietary technology, network effects, economies of scale, branding', 'Market share, switching costs, regulatory protection, technology', 'Innovation, distribution, talent, capital'], correctIndex: 1, explanation: 'Monopoly characteristics: 1. Proprietary technology (10× better), 2. Network effects (more valuable with more users), 3. Economies of scale, 4. Brand (durable perception of value).', sectionRef: 'The Anatomy of a Monopoly' },
    { question: 'What is the "Power Law" of startup investing?', options: ['Invest in powerful industries', 'One investment returns more than all others combined', 'Large funds outperform small ones', 'Startups grow exponentially or fail'], correctIndex: 1, explanation: 'Power Law: in venture, one investment returns more than the entire rest of the portfolio combined. Focus matters more than diversification — pick bets you believe can become huge.', sectionRef: 'The Power Law' },
    { question: 'What does Thiel mean by "last mover advantage"?', options: ['The last company to enter a market wins', 'Being the last great version of something is what creates durable value', 'Waiting for markets to mature before entering', 'Surviving until competitors fail'], correctIndex: 1, explanation: 'Last mover advantage: being the final dominant player in an important market. Not first-mover (that\'s often irrelevant) — but the last great version that locks in long-term value.', sectionRef: 'Last Mover Advantage' },
    { question: 'What is the "definite vs. indefinite" view of the future?', options: ['Known vs. unknown outcomes', 'Definite optimists plan and build; indefinite optimists wait for things to happen', 'Optimism vs. pessimism about the future', 'Short-term vs. long-term planning horizons'], correctIndex: 1, explanation: 'Definite optimist: the future will be better and you can make it that way. Indefinite optimist: the future will probably be better but you don\'t know how. Thiel says definite optimism is the right startup mindset.', sectionRef: 'Definite vs. Indefinite Optimism' },
    { question: 'Why are founding teams so important in Zero to One?', options: ['They set the company culture permanently', 'The founding moment creates durable DNA that is very hard to change later', 'They determine the company\'s valuation', 'They bring complementary skills'], correctIndex: 1, explanation: 'The founding decisions — who you hire, how you divide equity, what your culture is — create DNA that shapes the company for decades. Get it wrong at founding and it\'s nearly impossible to fix.', sectionRef: 'Founding Principles' },
    { question: 'What does Thiel say about "secrets"?', options: ['Trade secrets give competitive advantage', 'Great companies are built on secrets — things you know that others don\'t', 'Keep your strategy private', 'Secrets are illegal in public markets'], correctIndex: 1, explanation: 'Every great business has a secret — a truth about the world that others haven\'t seen. Finding that secret and building around it is the path to creating something truly valuable.', sectionRef: 'The Importance of Secrets' },
    { question: 'What is Thiel\'s critique of "lean startup" methodology?', options: ['It\'s too slow', 'It\'s appropriate for iteration but discourages bold, definite visions', 'It requires too much capital', 'It works for software but not hardware'], correctIndex: 1, explanation: 'Lean startup: iterate, pivot, fail fast. Thiel argues this is fine for finding product-market fit in a known space but fails to create genuinely new things. Bold visions require definite plans.', sectionRef: 'Against Lean Startup' },
  ],
  'shoe-dog': [
    { question: 'What was Phil Knight\'s original "Crazy Idea"?', options: ['Building the best running shoe', 'Importing Japanese running shoes (Tiger) and selling them in the US', 'Creating a sportswear brand', 'Manufacturing shoes in the US with Japanese quality'], correctIndex: 1, explanation: 'The Crazy Idea: import high-quality, low-cost Tiger running shoes from Japan and sell them in America. Knight borrowed $50 from his dad and sold from his car trunk at track meets.', sectionRef: 'The Crazy Idea' },
    { question: 'What threat nearly destroyed Nike before it became a real brand?', options: ['A competitor undercutting prices', 'Onitsuka threatening to end the partnership and find a new US distributor', 'A major quality recall', 'Financial insolvency'], correctIndex: 1, explanation: 'Onitsuka threatened to cut off Knight\'s supply and find another distributor. This crisis forced Knight to stop importing and create his own shoe — which became Nike.', sectionRef: 'The Onitsuka Crisis' },
    { question: 'How did Nike get its name?', options: ['After Phil Knight\'s mother', 'From the Greek goddess of victory, in a dream Jeff Johnson had', 'From a marketing consultant\'s suggestion', 'From a random brainstorm at the company'], correctIndex: 1, explanation: 'Jeff Johnson, Nike\'s first employee, received the name in a dream the night before the company needed to file trademark papers. Nike = Greek goddess of victory.', sectionRef: 'The Name' },
    { question: 'What is the key business lesson about cash flow in Shoe Dog?', options: ['Profitable businesses always have cash', 'Rapid growth consumes cash — revenue ≠ survival', 'Always maintain six months of operating expenses', 'Avoid bank loans at all costs'], correctIndex: 1, explanation: 'Nike was perpetually nearly bankrupt despite explosive sales. Growth requires inventory, which requires capital. The gap between making money and having cash nearly killed Nike multiple times.', sectionRef: 'The Cash Flow Lesson' },
    { question: 'What was the "Buttface" group?', options: ['Nike\'s internal brainstorming team', 'Knight\'s core early team that built Nike through irreverence and loyalty', 'A rival running shoe company', 'A Japanese distributor\'s nickname for Nike'], correctIndex: 1, explanation: 'The "Buttfaces" were Knight\'s inner circle of Nike managers — people who called each other terrible names but were completely loyal and built Nike from nothing to a global brand together.', sectionRef: 'The Buttfaces' },
    { question: 'What was Bowerman\'s contribution to Nike\'s technology?', options: ['He designed the Nike swoosh', 'He created the waffle sole by pouring rubber into his wife\'s waffle iron', 'He invented the air cushioning system', 'He designed the running spike'], correctIndex: 1, explanation: 'Bill Bowerman, Knight\'s college coach and co-founder, poured urethane rubber into his wife\'s waffle iron and created the waffle sole — one of the most innovative running shoe technologies ever.', sectionRef: 'The Waffle Sole' },
    { question: 'What was Nike\'s initial public offering (IPO) like?', options: ['It failed to raise the expected capital', 'It was a massive success but Knight felt empty afterward', 'It was delayed by legal issues', 'Knight refused to take Nike public for years'], correctIndex: 1, explanation: 'Nike\'s IPO was successful and made Knight wealthy. But he describes feeling surprisingly hollow — realizing he\'d been in love with the struggle, not the destination.', sectionRef: 'The IPO' },
    { question: 'What is the role of "crazy" people in Knight\'s story?', options: ['They are risks to avoid in business', 'The willing crazy ones — runners, early employees — built everything remarkable', 'Crazy ideas are dangerous without rational planning', 'Crazy people need to be managed by rational leaders'], correctIndex: 1, explanation: 'Knight says the story of Nike is a story of crazy people: crazy enough to believe in the mission when it made no financial sense. That craziness was the competitive advantage.', sectionRef: 'The Crazy Ones' },
    { question: 'What does Shoe Dog say about purpose in work?', options: ['Focus on the financial rewards to stay motivated', '"Don\'t settle for a career — seek a calling." Knight never saw Nike as a business.', 'Balance passion with practicality', 'Purpose matters less than execution'], correctIndex: 1, explanation: '"Don\'t settle for a job or even a career. Seek a calling." Knight had a religious conviction about shoes and running. That passion sustained him through years of near-bankruptcy and crisis.', sectionRef: 'The Purpose' },
    { question: 'How did Nike\'s relationship with athletes differentiate it?', options: ['Nike paid higher endorsement fees than competitors', 'Authentic partnerships with athletes who genuinely used the shoes', 'Nike invented celebrity endorsements in sports', 'Nike focused exclusively on professional athletes'], correctIndex: 1, explanation: 'Nike\'s athlete relationships felt authentic because they started with runners who actually used the shoes. Steve Prefontaine, for example, was a true believer — not just a paid spokesperson.', sectionRef: 'The Athlete Partnerships' },
  ],
  'rework': [
    { question: 'What is the core anti-conventional message of Rework?', options: ['Scale quickly to win markets', 'Reject conventional business wisdom — planning is guessing, meetings are toxic, growth isn\'t always good', 'Start lean and grow organically', 'Compete on product quality alone'], correctIndex: 1, explanation: 'Rework challenges everything: you don\'t need a business plan, outside funding, or a large team. Most conventional business advice is wrong for small companies.', sectionRef: 'The Core Message' },
    { question: 'What does "scratch your own itch" mean in Rework?', options: ['Self-motivated work is more productive', 'Build products that solve your own problems — you\'ll be your own best customer', 'Entrepreneurs must love what they do', 'Start with personal projects before going commercial'], correctIndex: 1, explanation: 'Scratch your own itch: build something you wish existed. Basecamp was built for 37signals\' own project management needs. You understand the problem intimately when it\'s yours.', sectionRef: 'Scratch Your Own Itch' },
    { question: 'Why do Fried and Hansson say "planning is guessing"?', options: ['Plans are always wrong', 'The future is too uncertain — committing to rigid plans prevents adaptation', 'Plans waste time that could be spent building', 'Business plans are only for investors'], correctIndex: 1, explanation: 'Planning implies you know the future. You don\'t. Make decisions when you have the best current information, not based on a plan you made in the past with less information.', sectionRef: 'Planning Is Guessing' },
    { question: 'What is the Rework approach to "do less than competitors"?', options: ['Cut corners to compete on price', 'Deliberately offer less product with fewer features done exceptionally well', 'Ignore competitor features', 'Focus on a niche too small for competitors to notice'], correctIndex: 1, explanation: 'Under-do your competitors: instead of more features, offer fewer but better ones. Being simpler and more focused beats trying to match every competitor feature.', sectionRef: 'Underdo Your Competitors' },
    { question: 'Why are meetings toxic according to Rework?', options: ['They reveal who the underperformers are', 'They\'re expensive, usually vague, require too many people, and rarely produce decisions', 'Remote teams can\'t have effective meetings', 'Meetings encourage groupthink'], correctIndex: 1, explanation: 'Meetings: usually 1 person too many, last too long, vague topics, produce vague results. A one-hour meeting with 5 people costs 5 hours of work. Replace with written communication.', sectionRef: 'Meetings Are Toxic' },
    { question: 'What does "launch now" mean?', options: ['Be first to market always', 'Ship the smallest version you\'re proud of — real feedback beats hypothetical planning', 'Launch on a specific date regardless of readiness', 'Soft-launch to a select audience first'], correctIndex: 1, explanation: '"Launch now": a less-than-perfect product in the world generates real feedback. A perfect product still on your hard drive generates nothing. Ship something real.', sectionRef: 'Launch Now' },
    { question: 'What does Rework say about "outteaching" competitors?', options: ['Become a thought leader with a newsletter', 'Share what you know — expertise publicly shared creates trust that advertising can\'t', 'Train your customers on your product', 'Build the best documentation in your industry'], correctIndex: 1, explanation: 'Outteach your competition: share your knowledge through blog posts, talks, tutorials. This builds trust and attracts customers who already believe in your expertise. It\'s marketing that doesn\'t feel like marketing.', sectionRef: 'Out-teach Your Competition' },
    { question: 'What is the Rework advice on "outside money"?', options: ['Always seek venture capital to scale', 'Avoid it if possible — it trades control for capital and changes your priorities', 'Crowdfunding is always better than VC', 'Get outside money only for hardware products'], correctIndex: 1, explanation: 'Outside money means outside control. Investors want growth (often at any cost). If you can build profitably without it, you preserve freedom to make decisions on your terms.', sectionRef: 'Outside Money' },
    { question: 'What does Rework say about "heroes"?', options: ['Celebrate team heroes to build culture', 'The "hero" culture (working 80-hour weeks as a badge of honor) is counterproductive', 'Every successful company needs a heroic founder', 'Heroes are essential in early-stage startups'], correctIndex: 1, explanation: 'The hero culture rewards unsustainable overwork. Someone who works 8 productive hours beats someone who works 16 unfocused ones. Workaholism is a disease, not a virtue.', sectionRef: 'Workaholism' },
    { question: 'What is the advice on "resumes and hiring"?', options: ['Always require formal credentials', 'Cover letters matter more than resumes — look for people who show their work and write well', 'Hire for culture fit over skills', 'Only hire people you\'ve worked with before'], correctIndex: 1, explanation: 'Rework: hire people who communicate well in writing (cover letters reveal this), who can show their work, and who demonstrate genuine interest — not just those with impressive credentials.', sectionRef: 'Hiring and Resumes' },
  ],
  'ikigai': [
    { question: 'What does "Ikigai" literally mean?', options: ['Meaning of life', 'Reason for being / reason to wake up in the morning', 'Life purpose', 'Happy work'], correctIndex: 1, explanation: '"Ikigai" combines "iki" (life) and "gai" (worth/value). It\'s the Japanese concept for one\'s reason for being — the intersection of passion, mission, vocation, and profession.', sectionRef: 'What Is Ikigai?' },
    { question: 'Where is Okinawa in the context of Ikigai?', options: ['The birthplace of the concept', 'A Blue Zone — one of the world\'s highest concentrations of centenarians', 'Where the authors conducted their research', 'The spiritual capital of Japan'], correctIndex: 1, explanation: 'Okinawa is a Blue Zone — a geographic area with unusual concentrations of people aged 100+. The book studies their lifestyle to extract the principles of longevity and happiness.', sectionRef: 'The Blue Zone' },
    { question: 'What is "hara hachi bu"?', options: ['A Japanese greeting', 'Eating until 80% full — a traditional Okinawan practice', 'A mindfulness meditation technique', 'The concept of living in the present moment'], correctIndex: 1, explanation: 'Hara hachi bu: eat until 80% full. By not overeating, Okinawans reduce cellular stress and inflammation. Confucius taught this principle 2,500 years ago.', sectionRef: 'Hara Hachi Bu' },
    { question: 'What is the relationship between ikigai and Flow?', options: ['Ikigai is a type of Flow state', 'Activities that produce Flow are likely connected to your ikigai', 'Flow is necessary to find your ikigai', 'They are unrelated concepts'], correctIndex: 1, explanation: 'When you\'re in Flow — completely absorbed, time disappearing — you\'re likely doing something connected to your ikigai. Following Flow experiences leads you to your purpose.', sectionRef: 'Ikigai and Flow' },
    { question: 'What do all Okinawan centenarians have in common?', options: ['They all do the same specific exercises', 'Clear purpose, daily movement, simple food, strong community, and a reason to get up each morning', 'They all live alone to reduce stress', 'They all follow a specific diet plan'], correctIndex: 1, explanation: 'Okinawan centenarians share: ikigai (purpose), natural daily movement, hara hachi bu (mindful eating), plant-based diet, strong social bonds (moai), and stress reduction through nature.', sectionRef: 'What Centenarians Share' },
    { question: 'What is "moai"?', options: ['A type of Japanese meditation', 'An informal social group that provides social support and community', 'A traditional Okinawan exercise', 'The concept of interdependence'], correctIndex: 1, explanation: 'Moai: a social support group you\'re part of for life. Members support each other emotionally and financially. The social connection is a key longevity factor in Okinawa.', sectionRef: 'Moai' },
    { question: 'The four components of ikigai are:', options: ['Passion, Purpose, Income, Balance', 'What you love, What you\'re good at, What the world needs, What you can be paid for', 'Work, Health, Community, Nature', 'Joy, Meaning, Achievement, Relationships'], correctIndex: 1, explanation: 'The ikigai Venn diagram: 1. What you love (passion), 2. What you\'re good at (profession), 3. What the world needs (mission), 4. What you can be paid for (vocation). True ikigai sits at all four intersections.', sectionRef: 'The Ikigai Venn Diagram' },
  ],
  'the-power-of-now': [
    { question: 'What is Tolle\'s core teaching?', options: ['The future is what you should focus on', 'The present moment is the only moment that truly exists; most suffering comes from past/future thinking', 'Meditation is the path to enlightenment', 'Accepting your circumstances is the key to peace'], correctIndex: 1, explanation: 'The core teaching: Be Here Now. The present moment always "is." Your mind creates suffering by living in memory (past) or anticipation (future). Presence is the cure.', sectionRef: 'The Core Teaching' },
    { question: 'What is the "Pain Body"?', options: ['Physical pain stored in the body from injuries', 'An accumulated energy field of past emotional pain that feeds on negative thoughts', 'The ego\'s resistance to spiritual growth', 'Chronic stress responses in the nervous system'], correctIndex: 1, explanation: 'The Pain Body: a semi-autonomous entity made of old emotional pain. It seeks to feed on negative thoughts and drama. Recognizing it — "this is my pain body" — begins to dissolve its power.', sectionRef: 'The Pain Body' },
    { question: 'What is the difference between "clock time" and "psychological time"?', options: ['One is objective; one is subjective', 'Clock time is practical planning; psychological time is unhealthy past/future obsession', 'Clock time is measured in hours; psychological time in events', 'Productive people use clock time; unproductive people use psychological time'], correctIndex: 1, explanation: 'Clock time: practical (setting a meeting, learning from the past to plan). Psychological time: pathological (obsessing over past mistakes, anxious future-projecting). Use clock time, not psychological time.', sectionRef: 'Clock Time vs. Psychological Time' },
    { question: 'What does "watching the thinker" mean?', options: ['Observing other people\'s thoughts', 'Noticing your thoughts without identifying with them — becoming the observer', 'Critical thinking about your own ideas', 'Journaling your daily thoughts'], correctIndex: 1, explanation: 'Watch the thinker: notice your own thinking from a place of awareness. "I notice I\'m thinking X" rather than "I am thinking X." This gap between you and your thought is the beginning of consciousness.', sectionRef: 'Watching the Thinker' },
    { question: 'What is "acceptance" in Tolle\'s teaching?', options: ['Giving up and surrendering to circumstances', 'Fully acknowledging what is, without resistance — then taking action from that space', 'Agreement with everything that happens', 'A passive attitude toward problems'], correctIndex: 1, explanation: 'Acceptance: not resignation, but total acknowledgment of what is. From acceptance, you can act effectively. Resistance ("this shouldn\'t be happening") is the source of suffering.', sectionRef: 'Acceptance and Surrender' },
    { question: 'What is the "ego" according to Tolle?', options: ['Your sense of self-worth', 'The identification with your mind — the false sense of separate self built from thoughts, stories, and emotions', 'Your competitive drive', 'Your personality and character traits'], correctIndex: 1, explanation: 'The ego is not your true self — it\'s an overlay of identification with thought. It creates separation, drama, and suffering. True self is the awareness behind thought, not the thought itself.', sectionRef: 'The Ego' },
    { question: 'What does Tolle mean by "the Now is the only door to inner peace"?', options: ['Meditation practices bring peace', 'You cannot experience peace in the past or future — only in this moment', 'Peace requires a quiet environment', 'Inner peace comes from resolving past conflicts'], correctIndex: 1, explanation: 'Inner peace doesn\'t live in the future ("I\'ll be happy when...") or the past. It\'s only accessible right now. Every moment you are present is a moment of genuine peace.', sectionRef: 'The Present Moment' },
  ],
}
